policies.inbound:



    @(context.Subscription?.Id ?? "anonymous")



    2023-06-01





<set-variable name="wasStreaming" value="@(context.Request.Body.As(preserveContent: true)["stream"]?.Value() == true)" />
@{
    var body = context.Request.Body.As<JObject>(preserveContent: true);
    var messages = body["messages"] as JArray ?? new JArray();

    // Separate system message(s) from the conversation history.
    // Anthropic exposes system as a top-level string field, not a role in messages[].
    string systemPrompt = null;
    var anthropicMessages = new JArray();
    foreach (JObject msg in messages) {
        var role = msg["role"]?.ToString();
        if (role == "system") {
            var c = msg["content"]?.ToString() ?? "";
            systemPrompt = systemPrompt == null ? c : systemPrompt + "\n" + c;
        } else {
            anthropicMessages.Add(msg);
        }
    }

    var result = new JObject();
    result["model"]    = body["model"];
    result["messages"] = anthropicMessages;
    if (systemPrompt != null) { result["system"] = systemPrompt; }

    // max_tokens is required by the Anthropic API (OpenAI makes it optional).
    result["max_tokens"] = body["max_tokens"] ?? (JToken)4096;

    // Pass through optional sampling parameters.
    if (body["temperature"] != null) { result["temperature"] = body["temperature"]; }
    if (body["top_p"]       != null) { result["top_p"]       = body["top_p"]; }

    // OpenAI "stop" can be a string or array; Anthropic needs an array.
    if (body["stop"] != null) {
        result["stop_sequences"] = body["stop"].Type == JTokenType.String
            ? new JArray(body["stop"])
            : body["stop"];
    }

    // Always send non-streaming to Anthropic; outbound policy re-encodes as SSE
    // when the wasStreaming context variable (set above) is true.
    result["stream"] = false;

    return result.ToString();
}

when.set-body:
@{
                    var body = context.Response.Body.As<JObject>(preserveContent: true);

                    // Concatenate all text content blocks.
                    var sb = new System.Text.StringBuilder();
                    var contentArr = body["content"] as JArray;
                    if (contentArr != null) {
                        foreach (JObject block in contentArr) {
                            if (block["type"]?.ToString() == "text") {
                                sb.Append(block["text"]?.ToString() ?? "");
                            }
                        }
                    }

                    // Map Anthropic stop_reason to OpenAI finish_reason.
                    var stopReason = body["stop_reason"]?.ToString() ?? "end_turn";
                    var finishReason = stopReason == "end_turn"   ? "stop"
                                     : stopReason == "max_tokens" ? "length"
                                     : stopReason == "tool_use"   ? "tool_calls"
                                     : "stop";

                    var usage = body["usage"] as JObject ?? new JObject();
                    var inputTokens  = usage["input_tokens"]?.Value<int>()  ?? 0;
                    var outputTokens = usage["output_tokens"]?.Value<int>() ?? 0;

                    var id      = "chatcmpl-" + (body["id"]?.ToString() ?? "");
                    var model   = body["model"]?.ToString() ?? "";
                    var created = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
                    var content = sb.ToString();

                    var wasStreaming = context.Variables.ContainsKey("wasStreaming")
                                   && (bool)context.Variables["wasStreaming"];

                    if (wasStreaming) {
                        // Re-encode as OpenAI SSE.  Three chunks:
                        //   1. role announcement  2. full content  3. finish signal + [DONE]
                        var c1 = new JObject {
                            ["id"] = id, ["object"] = "chat.completion.chunk",
                            ["created"] = created, ["model"] = model,
                            ["choices"] = new JArray { new JObject {
                                ["index"] = 0,
                                ["delta"] = new JObject { ["role"] = "assistant", ["content"] = "" },
                                ["finish_reason"] = JValue.CreateNull()
                            }}
                        };
                        var c2 = new JObject {
                            ["id"] = id, ["object"] = "chat.completion.chunk",
                            ["created"] = created, ["model"] = model,
                            ["choices"] = new JArray { new JObject {
                                ["index"] = 0,
                                ["delta"] = new JObject { ["content"] = content },
                                ["finish_reason"] = JValue.CreateNull()
                            }}
                        };
                        var c3 = new JObject {
                            ["id"] = id, ["object"] = "chat.completion.chunk",
                            ["created"] = created, ["model"] = model,
                            ["choices"] = new JArray { new JObject {
                                ["index"] = 0,
                                ["delta"] = new JObject(),
                                ["finish_reason"] = finishReason
                            }}
                        };
                        return "data: " + c1.ToString(Newtonsoft.Json.Formatting.None)
                             + "\n\ndata: " + c2.ToString(Newtonsoft.Json.Formatting.None)
                             + "\n\ndata: " + c3.ToString(Newtonsoft.Json.Formatting.None)
                             + "\n\ndata: [DONE]\n\n";
                    }

                    var openAiBody = new JObject {
                        ["id"]      = id,
                        ["object"]  = "chat.completion",
                        ["created"] = created,
                        ["model"]   = model,
                        ["choices"] = new JArray {
                            new JObject {
                                ["index"]         = 0,
                                ["message"]       = new JObject {
                                    ["role"]    = "assistant",
                                    ["content"] = content
                                },
                                ["finish_reason"] = finishReason,
                                ["logprobs"]      = JValue.CreateNull()
                            }
                        },
                        ["usage"] = new JObject {
                            ["prompt_tokens"]     = inputTokens,
                            ["completion_tokens"] = outputTokens,
                            ["total_tokens"]      = inputTokens + outputTokens
                        }
                    };

                    return openAiBody.ToString();
                }
